3	export type Item = {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	};
9	
10	export type QuoteInput = {
11	  items: Item[];
12	  customerYears: number;
13	  previousContracts: number;
14	};
15	
16	const PROCESSING_FEE = 5;
17	const COMPONENT_BLOCK_SIZE = 3;
18	const COMPONENT_BLOCK_PREMIUM = 60;
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	
21	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	function groupByType(items: Item[]): Map<string, Item[]> {
31	  const groups = new Map<string, Item[]>();
32	  for (const item of items) {
33	    const group = groups.get(item.type) ?? [];
34	    group.push(item);
35	    groups.set(item.type, group);
36	  }
37	  return groups;
38	}
39	
40	function premiumForGroup(type: string, group: Item[]): number {
41	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
42	    return COMPONENT_BLOCK_PREMIUM;
43	  }
44	  return group.length * BASE_PREMIUM_BY_TYPE[type];
45	}
46	
47	function itemPremium(item: Item): number {
48	  let premium = BASE_PREMIUM_BY_TYPE[item.type];
49	  if (item.cursed) {
50	    premium += BASE_PREMIUM_BY_TYPE[item.type] * 0.5;
51	  }
52	  return premium;
53	}
54	
55	function premiumForItems(items: Item[]): number {
56	  // If any item has modifiers (cursed), compute per-item; else group logic
57	  const hasModifiers = items.some((item) => item.cursed);
58	  if (hasModifiers) {
59	    let total = 0;
60	    for (const item of items) {
61	      total += itemPremium(item);
62	    }
63	    return total;
64	  }
65	  let total = 0;
66	  for (const [type, group] of groupByType(items)) {
67	    total += premiumForGroup(type, group);
68	  }
69	  return total;
70	}
71	
72	export function quote(input: QuoteInput): number {
73	  let premium = premiumForItems(input.items);
74	  const hasModifiers = input.items.some((item) => item.cursed);
75	  if (
76	    hasModifiers &&
77	    input.customerYears === 0 &&
78	    input.previousContracts === 0
79	  ) {
80	    const baseTotal = input.items.reduce(
81	      (sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type],
82	      0,
83	    );
84	    premium += baseTotal * 0.1;
85	  }
86	  return premium + PROCESSING_FEE;
87	}
