function premiumForGroup(type: string, group: Item[]): number {
  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
    return COMPONENT_BLOCK_PREMIUM;
  }
  return group.length * BASE_PREMIUM_BY_TYPE[type];
}

function itemPremium(item: Item): number {
  let premium = BASE_PREMIUM_BY_TYPE[item.type];
  if (item.cursed) {
    premium += BASE_PREMIUM_BY_TYPE[item.type] * 0.5;
  }
  return premium;
}

function premiumForItems(items: Item[]): number {
  // If any item has modifiers (cursed), compute per-item; else group logic
  const hasModifiers = items.some((item) => item.cursed);
  if (hasModifiers) {
    let total = 0;
    for (const item of items) {
      total += itemPremium(item);
    }
    return total;
  }
  let total = 0;
  for (const [type, group] of groupByType(items)) {
    total += premiumForGroup(type, group);
  }
  return total;
}

export function quote(input: QuoteInput): number {
  let premium = premiumForItems(input.items);
  const hasModifiers = input.items.some((item) => item.cursed);
  if (
    hasModifiers &&
    input.customerYears === 0 &&
    input.previousContracts === 0
  ) {
    const baseTotal = input.items.reduce(
      (sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type],
      0,
    );
    premium += baseTotal * 0.1;
  }
  return premium + PROCESSING_FEE;
}

